#include "markforge/hooks.h"
void mf_hook_manager_init(mf_hook_manager_t*m){ if(m) memset(m,0,sizeof(*m)); }
void mf_hook_manager_destroy(mf_hook_manager_t*m){ if(m){ free(m->entries); memset(m,0,sizeof(*m)); } }
mf_result_t mf_hook_register(mf_hook_manager_t*m,mf_hook_event_t e,mf_hook_fn fn,void*ctx){ mf_hook_entry_t*p; size_t nc; if(!m||!fn)return MF_ERROR_INVALID; if(m->count==m->capacity){ nc=m->capacity?m->capacity*2U:16U; p=(mf_hook_entry_t*)realloc(m->entries,nc*sizeof(*p)); if(!p)return MF_ERROR_NOMEM; m->entries=p; m->capacity=nc;} m->entries[m->count].event=e; m->entries[m->count].fn=fn; m->entries[m->count].ctx=ctx; m->count++; return MF_OK; }
int mf_hook_emit(mf_hook_manager_t*m,mf_hook_event_t e,void*data){ size_t i; int rc=0; if(!m)return 0; for(i=0;i<m->count;i++) if(m->entries[i].event==e) rc|=m->entries[i].fn(e,data,m->entries[i].ctx); return rc; }
const char*mf_hook_event_name(mf_hook_event_t e){ switch(e){case MF_HOOK_BEFORE_PARSING:return"before_parsing";case MF_HOOK_AFTER_PARSING:return"after_parsing";case MF_HOOK_BEFORE_RENDERING:return"before_rendering";case MF_HOOK_AFTER_RENDERING:return"after_rendering";case MF_HOOK_CONFIGURATION_LOADED:return"configuration_loaded";case MF_HOOK_PLUGIN_LOADED:return"plugin_loaded";case MF_HOOK_PLUGIN_UNLOADED:return"plugin_unloaded";case MF_HOOK_RENDERER_SELECTED:return"renderer_selected";case MF_HOOK_FORMATTER_STARTED:return"formatter_started";case MF_HOOK_FORMATTER_FINISHED:return"formatter_finished";default:return"unknown";} }
